  ('optometrist-moex-03686', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關人類免疫缺乏病毒（human immunodeficiency virus, HIV）感染的敘述，下列何者錯誤？', '["人類免疫缺乏病毒可在眼淚中測到", "硬式隱形眼鏡試戴片可用雙氧系統清潔液消毒", "玻璃體和房水中不會出現人類免疫缺乏病毒", "軟式隱形眼鏡試戴片可用雙氧系統清潔液消毒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
